import { Tabs } from '@tale-ui/react/tabs';
import { Icon } from '@tale-ui/react/icon';
import { Bell, Lock, User } from 'lucide-react';

export function TabsWithIcons() {
  return (
    <Tabs.Root defaultSelectedKey="account">
      <Tabs.List>
        <Tabs.Tab id="account" icon={<Icon icon={User} size="sm" />}>Account</Tabs.Tab>
        <Tabs.Tab id="security" icon={<Icon icon={Lock} size="sm" />}>Security</Tabs.Tab>
        <Tabs.Tab id="notifications" icon={<Icon icon={Bell} size="sm" />}>Notifications</Tabs.Tab>
        <Tabs.Indicator />
      </Tabs.List>
      <Tabs.Panel id="account">
        <p>Manage profile details, email address, and account preferences.</p>
      </Tabs.Panel>
      <Tabs.Panel id="security">
        <p>Update passwords, passkeys, and two-factor authentication settings.</p>
      </Tabs.Panel>
      <Tabs.Panel id="notifications">
        <p>Choose when to receive email, push, and in-app notifications.</p>
      </Tabs.Panel>
    </Tabs.Root>
  );
}
